 }}\n{{eqn | ll= \leadsto 
 | l = \exists s_1 \in S_1: \tuple {s_1, t} 
 | o = \in 
 | r = \RR \land \exists s_2 \in S_2: \tuple {s_2, t} \in \RR 
 | c = {{Defof|Relation}} 
 }}\n{{eqn | ll= \leadsto 
